     1→//! Task complexity scoring for intelligent model routing.
     2→//!
     3→//! This module implements complexity analysis (0-100 scale) to help route
     4→//! tasks to appropriate AI models. Unlike priority scoring which determines
     5→//! execution order, complexity scoring determines *which model* should handle
     6→//! a task.
     7→//!
     8→//! ## Complexity Factors
     9→//!
    10→//! - **Title/Description Analysis**: Keywords indicating complexity
    11→//!   - "refactor", "architecture", "redesign" → high complexity
    12→//!   - "fix", "update", "tweak" → low complexity
    13→//! - **Label Analysis**: Labels like "complex", "architecture"
    14→//! - **File Count**: More files = more complex
    15→//! - **Blocking Dependencies**: Tasks blocking others are often more complex
    16→//! - **Task Type**: Bugs can be simple or complex, features often complex
    17→//!
    18→//! ## Routing Thresholds
    19→//!
    20→//! - **Score 0-30**: Simple tasks → Budget tier (Haiku, DeepSeek)
    21→//! - **Score 31-60**: Moderate tasks → Standard tier (Sonnet, GPT-4)
    22→//! - **Score 61-100**: Complex tasks → Premium tier (Opus, O1)
    23→//!
    24→//! ## Usage
    25→//!
    26→//! ```no_run
    27→//! use forge_worker::complexity::{ComplexityScorer, TaskContext};
    28→//!
    29→//! let scorer = ComplexityScorer::new();
    30→//!
    31→//! let context = TaskContext {
    32→//!     title: "Refactor authentication system for multi-tenant support".to_string(),
    33→//!     description: Some("Redesign the auth flow...".to_string()),
    34→//!     labels: vec!["architecture".to_string(), "complex".to_string()],
    35→//!     file_count: Some(12),
    36→//!     blocks_count: 3,
    37→//!     is_bug: false,
    38→//!     is_feature: true,
    39→//! };
    40→//!
    41→//! let score = scorer.score(&context);
    42→//! println!("Complexity: {} → {:?}", score.score, score.tier());
    43→//! ```
    44→
    45→use serde::{Deserialize, Serialize};
    46→
    47→/// Default weight for title analysis.
    48→const TITLE_WEIGHT: f64 = 0.30;
    49→
    50→/// Default weight for label analysis.
    51→const LABEL_WEIGHT: f64 = 0.25;
    52→
    53→/// Default weight for file count.
    54→const FILE_COUNT_WEIGHT: f64 = 0.20;
    55→
    56→/// Default weight for blocking dependencies.
    57→const BLOCKS_WEIGHT: f64 = 0.15;
    58→
    59→/// Default weight for task type.
    60→const TYPE_WEIGHT: f64 = 0.10;
    61→
    62→/// Configuration for the complexity scorer.
    63→#[derive(Debug, Clone, Serialize, Deserialize)]
    64→pub struct ComplexityConfig {
    65→    /// Weight for title/description analysis
    66→    pub title_weight: f64,
    67→
    68→    /// Weight for label analysis
    69→    pub label_weight: f64,
    70→
    71→    /// Weight for file count
    72→    pub file_count_weight: f64,
    73→
    74→    /// Weight for blocking dependencies
    75→    pub blocks_weight: f64,
    76→
    77→    /// Weight for task type
    78→    pub type_weight: f64,
    79→
    80→    /// Maximum files to consider (files beyond this don't add complexity)
    81→    pub max_file_count: usize,
    82→
    83→    /// Maximum blocking dependencies to consider
    84→    pub max_blocks: usize,
    85→}
    86→
    87→impl Default for ComplexityConfig {
    88→    fn default() -> Self {
    89→        Self {
    90→            title_weight: TITLE_WEIGHT,
    91→            label_weight: LABEL_WEIGHT,
    92→            file_count_weight: FILE_COUNT_WEIGHT,
    93→            blocks_weight: BLOCKS_WEIGHT,
    94→            type_weight: TYPE_WEIGHT,
    95→            max_file_count: 20,
    96→            max_blocks: 5,
    97→        }
    98→    }
    99→}
   100→
   101→impl ComplexityConfig {
   102→    /// Create a new config with default values.
   103→    pub fn new() -> Self {
   104→        Self::default()
   105→    }
   106→
   107→    /// Validate that weights sum to approximately 1.0.
   108→    pub fn validate(&self) -> Result<(), String> {
   109→        let sum = self.title_weight
   110→            + self.label_weight
   111→            + self.file_count_weight
   112→            + self.blocks_weight
   113→            + self.type_weight;
   114→        let tolerance = 0.05;
   115→
   116→        if (sum - 1.0).abs() > tolerance {
   117→            return Err(format!(
   118→                "Complexity weights should sum to ~1.0, got {:.3}",
   119→                sum
   120→            ));
   121→        }
   122→
   123→        Ok(())
   124→    }
   125→}
