   127→/// Context about a task for complexity analysis.
   128→#[derive(Debug, Clone, Default)]
   129→pub struct TaskContext {
   130→    /// Task title/summary
   131→    pub title: String,
   132→
   133→    /// Optional detailed description
   134→    pub description: Option<String>,
   135→
   136→    /// Labels attached to the task
   137→    pub labels: Vec<String>,
   138→
   139→    /// Number of files involved (if known)
   140→    pub file_count: Option<usize>,
   141→
   142→    /// Number of other tasks this task blocks
   143→    pub blocks_count: usize,
   144→
   145→    /// Whether this is a bug fix
   146→    pub is_bug: bool,
   147→
   148→    /// Whether this is a new feature
   149→    pub is_feature: bool,
   150→
   151→    /// Whether this requires complex reasoning
   152→    pub requires_reasoning: bool,
   153→}
   154→
   155→impl TaskContext {
   156→    /// Create a new task context with just a title.
   157→    pub fn new(title: impl Into<String>) -> Self {
   158→        Self {
   159→            title: title.into(),
   160→            ..Default::default()
   161→        }
   162→    }
   163→
   164→    /// Add description.
   165→    pub fn with_description(mut self, desc: impl Into<String>) -> Self {
   166→        self.description = Some(desc.into());
   167→        self
   168→    }
   169→
   170→    /// Add labels.
   171→    pub fn with_labels(mut self, labels: Vec<String>) -> Self {
   172→        self.labels = labels;
   173→        self
   174→    }
   175→
   176→    /// Set file count.
   177→    pub fn with_file_count(mut self, count: usize) -> Self {
   178→        self.file_count = Some(count);
   179→        self
   180→    }
   181→
   182→    /// Set blocks count.
   183→    pub fn with_blocks(mut self, count: usize) -> Self {
   184→        self.blocks_count = count;
   185→        self
   186→    }
   187→
   188→    /// Mark as bug.
   189→    pub fn as_bug(mut self) -> Self {
   190→        self.is_bug = true;
   191→        self.is_feature = false;
   192→        self
   193→    }
   194→
   195→    /// Mark as feature.
   196→    pub fn as_feature(mut self) -> Self {
   197→        self.is_feature = true;
   198→        self.is_bug = false;
   199→        self
   200→    }
   201→
   202→    /// Set requires reasoning.
   203→    pub fn with_reasoning(mut self, requires: bool) -> Self {
   204→        self.requires_reasoning = requires;
   205→        self
   206→    }
   207→}
