   209→/// Result of complexity scoring with breakdown.
   210→#[derive(Debug, Clone, Serialize, Deserialize)]
   211→pub struct ComplexityScore {
   212→    /// Total complexity score (0-100)
   213→    pub score: u32,
   214→
   215→    /// Title analysis contribution (0-100)
   216→    pub title_score: u32,
   217→
   218→    /// Label analysis contribution (0-100)
   219→    pub label_score: u32,
   220→
   221→    /// File count contribution (0-100)
   222→    pub file_count_score: u32,
   223→
   224→    /// Blocking dependencies contribution (0-100)
   225→    pub blocks_score: u32,
   226→
   227→    /// Task type contribution (0-100)
   228→    pub type_score: u32,
   229→
   230→    /// Detected complexity indicators
   231→    pub indicators: Vec<String>,
   232→}
   233→
   234→impl ComplexityScore {
   235→    /// Get the recommended model tier for this complexity.
   236→    pub fn tier(&self) -> ComplexityTier {
   237→        match self.score {
   238→            0..=30 => ComplexityTier::Budget,
   239→            31..=60 => ComplexityTier::Standard,
   240→            61..=100 => ComplexityTier::Premium,
   241→            _ => ComplexityTier::Standard,
   242→        }
   243→    }
   244→
   245→    /// Check if this is a simple task.
   246→    pub fn is_simple(&self) -> bool {
   247→        self.score <= 30
   248→    }
   249→
   250→    /// Check if this is a complex task.
   251→    pub fn is_complex(&self) -> bool {
   252→        self.score >= 61
   253→    }
   254→}
   255→
   256→/// Model tier recommendation based on complexity.
   257→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
   258→#[serde(rename_all = "snake_case")]
   259→pub enum ComplexityTier {
   260→    /// Simple tasks - use budget models
   261→    Budget,
   262→    /// Moderate tasks - use standard models
   263→    Standard,
   264→    /// Complex tasks - use premium models
   265→    Premium,
   266→}
   267→
   268→impl std::fmt::Display for ComplexityTier {
   269→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
   270→        match self {
   271→            Self::Budget => write!(f, "budget"),
   272→            Self::Standard => write!(f, "standard"),
   273→            Self::Premium => write!(f, "premium"),
   274→        }
   275→    }
   276→}
