   362→/// The complexity scorer engine.
   363→#[derive(Debug, Clone)]
   364→pub struct ComplexityScorer {
   365→    config: ComplexityConfig,
   366→}
   367→
   368→impl Default for ComplexityScorer {
   369→    fn default() -> Self {
   370→        Self::new()
   371→    }
   372→}
   373→
   374→impl ComplexityScorer {
   375→    /// Create a new scorer with default configuration.
   376→    pub fn new() -> Self {
   377→        Self {
   378→            config: ComplexityConfig::default(),
   379→        }
   380→    }
   381→
   382→    /// Create a scorer with custom configuration.
   383→    pub fn with_config(config: ComplexityConfig) -> Self {
   384→        Self { config }
   385→    }
   386→
   387→    /// Get the current configuration.
   388→    pub fn config(&self) -> &ComplexityConfig {
   389→        &self.config
   390→    }
   391→
   392→    /// Calculate complexity score for a task.
   393→    pub fn score(&self, context: &TaskContext) -> ComplexityScore {
   394→        let mut indicators = Vec::new();
   395→
   396→        // Analyze title/description
   397→        let title_score = self.analyze_title(context, &mut indicators);
   398→
   399→        // Analyze labels
   400→        let label_score = self.analyze_labels(context, &mut indicators);
   401→
   402→        // Analyze file count
   403→        let file_count_score = self.analyze_file_count(context, &mut indicators);
   404→
   405→        // Analyze blocking dependencies
   406→        let blocks_score = self.analyze_blocks(context, &mut indicators);
   407→
   408→        // Analyze task type
   409→        let type_score = self.analyze_type(context, &mut indicators);
   410→
   411→        // Calculate weighted total
   412→        let total = (title_score as f64 * self.config.title_weight)
   413→            + (label_score as f64 * self.config.label_weight)
   414→            + (file_count_score as f64 * self.config.file_count_weight)
   415→            + (blocks_score as f64 * self.config.blocks_weight)
   416→            + (type_score as f64 * self.config.type_weight);
   417→
   418→        let score = total.round().min(100.0).max(0.0) as u32;
   419→
   420→        ComplexityScore {
   421→            score,
   422→            title_score,
   423→            label_score,
   424→            file_count_score,
   425→            blocks_score,
   426→            type_score,
   427→            indicators,
   428→        }
   429→    }
   430→
   431→    /// Quick complexity score without full context.
   432→    pub fn quick_score(&self, title: &str, labels: &[String]) -> u32 {
   433→        let context = TaskContext::new(title).with_labels(labels.to_vec());
   434→        self.score(&context).score
   435→    }
   436→
   437→    /// Analyze title and description for complexity indicators.
   438→    fn analyze_title(&self, context: &TaskContext, indicators: &mut Vec<String>) -> u32 {
   439→        let text = format!(
   440→            "{} {}",
   441→            context.title,
   442→            context.description.as_deref().unwrap_or("")
   443→        )
   444→        .to_lowercase();
   445→
   446→        let mut score = 50.0; // Start at neutral
   447→
   448→        // Check for high complexity keywords
   449→        for keyword in HIGH_COMPLEXITY_KEYWORDS {
   450→            if text.contains(keyword) {
   451→                score += 8.0;
   452→                indicators.push(format!("keyword:{}", keyword));
   453→            }
   454→        }
   455→
   456→        // Check for low complexity keywords
   457→        for keyword in LOW_COMPLEXITY_KEYWORDS {
   458→            if text.contains(keyword) {
   459→                score -= 8.0;
   460→                indicators.push(format!("simple:{}", keyword));
   461→            }
   462→        }
   463→
   464→        // Check for reasoning requirement
   465→        if context.requires_reasoning {
   466→            score += 15.0;
   467→            indicators.push("requires_reasoning".to_string());
   468→        }
   469→
   470→        // Length heuristic: very short titles are often simple
   471→        if context.title.len() < 20 {
   472→            score -= 5.0;
   473→        } else if context.title.len() > 80 {
   474→            score += 5.0;
   475→        }
   476→
   477→        score.round().min(100.0).max(0.0) as u32
   478→    }
   479→
   480→    /// Analyze labels for complexity indicators.
   481→    fn analyze_labels(&self, context: &TaskContext, indicators: &mut Vec<String>) -> u32 {
   482→        let mut score = 50.0; // Start at neutral
   483→
   484→        for label in &context.labels {
   485→            let label_lower = label.to_lowercase();
   486→
   487→            // Check high complexity labels
   488→            for high_label in HIGH_COMPLEXITY_LABELS {
   489→                if label_lower.contains(high_label) {
   490→                    score += 12.0;
   491→                    indicators.push(format!("label:{}", label));
   492→                    break;
   493→                }
   494→            }
   495→
   496→            // Check low complexity labels
   497→            for low_label in LOW_COMPLEXITY_LABELS {
   498→                if label_lower.contains(low_label) {
   499→                    score -= 10.0;
   500→                    indicators.push(format!("simple_label:{}", label));
   501→                    break;
   502→                }
   503→            }
   504→        }
   505→
   506→        score.round().min(100.0).max(0.0) as u32
   507→    }
   508→
   509→    /// Analyze file count for complexity.
   510→    fn analyze_file_count(&self, context: &TaskContext, indicators: &mut Vec<String>) -> u32 {
   511→        match context.file_count {
   512→            Some(count) if count == 0 => 30,
   513→            Some(count) if count == 1 => 35,
   514→            Some(count) if count <= 3 => 45,
   515→            Some(count) if count <= 5 => 55,
   516→            Some(count) if count <= 10 => 65,
   517→            Some(count) => {
   518→                let capped = count.min(self.config.max_file_count);
   519→                // Scale from 65 to 100 based on files 10-20+
   520→                let extra = ((capped - 10) as f64 / 10.0 * 35.0).min(35.0);
   521→                if count > 5 {
   522→                    indicators.push(format!("files:{}", count));
   523→                }
   524→                (65.0 + extra).min(100.0) as u32
   525→            }
   526→            None => 50, // Unknown, assume moderate
   527→        }
   528→    }
   529→
   530→    /// Analyze blocking dependencies.
   531→    fn analyze_blocks(&self, context: &TaskContext, indicators: &mut Vec<String>) -> u32 {
   532→        match context.blocks_count {
   533→            0 => 40,
   534→            1 => 50,
   535→            2 => 60,
   536→            3..=5 => {
   537→                indicators.push(format!("blocks:{}", context.blocks_count));
   538→                70
   539→            }
   540→            _ => {
   541→                indicators.push(format!("blocks:{}", context.blocks_count));
   542→                85
   543→            }
   544→        }
   545→    }
   546→
   547→    /// Analyze task type.
   548→    fn analyze_type(&self, context: &TaskContext, indicators: &mut Vec<String>) -> u32 {
   549→        // Base score depends on task type
   550→        let base = if context.is_feature {
   551→            indicators.push("feature".to_string());
   552→            60 // Features tend to be more complex
   553→        } else if context.is_bug {
   554→            // Bugs vary widely - start neutral
   555→            50
   556→        } else {
   557→            50 // Unknown type
   558→        };
   559→
   560→        // Reasoning requirement overrides
   561→        if context.requires_reasoning {
   562→            return 80;
   563→        }
   564→
   565→        base
   566→    }
   567→}
