   569→#[cfg(test)]
   570→mod tests {
   571→    use super::*;
   572→
   573→    #[test]
   574→    fn test_config_validation() {
   575→        let config = ComplexityConfig::default();
   576→        assert!(config.validate().is_ok());
   577→    }
   578→
   579→    #[test]
   580→    fn test_simple_task() {
   581→        let scorer = ComplexityScorer::new();
   582→
   583→        let context = TaskContext::new("Fix typo in README")
   584→            .with_labels(vec!["documentation".to_string()])
   585→            .with_file_count(1);
   586→
   587→        let score = scorer.score(&context);
   588→        assert!(score.score <= 40, "Simple task should have low score, got {}", score.score);
   589→        assert!(score.is_simple());
   590→    }
   591→
   592→    #[test]
   593→    fn test_complex_task() {
   594→        let scorer = ComplexityScorer::new();
   595→
   596→        let context = TaskContext::new("Refactor authentication system for multi-tenant support")
   597→            .with_labels(vec!["architecture".to_string(), "complex".to_string()])
   598→            .with_file_count(15)
   599→            .with_blocks(3)
   600→            .as_feature();
   601→
   602→        let score = scorer.score(&context);
   603→        assert!(score.score >= 60, "Complex task should have high score, got {}", score.score);
   604→        assert!(score.is_complex());
   605→        assert_eq!(score.tier(), ComplexityTier::Premium);
   606→    }
   607→
   608→    #[test]
   609→    fn test_moderate_task() {
   610→        let scorer = ComplexityScorer::new();
   611→
   612→        let context = TaskContext::new("Update user profile page styling")
   613→            .with_file_count(3);
   614→
   615→        let score = scorer.score(&context);
   616→        // Should be moderate (not simple, not complex)
   617→        assert!(score.score > 30 && score.score < 70);
   618→        assert_eq!(score.tier(), ComplexityTier::Standard);
   619→    }
   620→
   621→    #[test]
   622→    fn test_quick_score() {
   623→        let scorer = ComplexityScorer::new();
   624→
   625→        let simple = scorer.quick_score("Fix typo", &[]);
   626→        assert!(simple <= 50);
   627→
   628→        let complex = scorer.quick_score("Refactor architecture for scalability", &["complex".to_string()]);
   629→        assert!(complex >= 50);
   630→    }
   631→
   632→    #[test]
   633→    fn test_reasoning_override() {
   634→        let scorer = ComplexityScorer::new();
   635→
   636→        let context = TaskContext::new("Simple task")
   637→            .with_reasoning(true);
   638→
   639→        let score = scorer.score(&context);
   640→        assert!(score.score >= 50, "Reasoning requirement should boost score");
   641→    }
   642→
   643→    #[test]
   644→    fn test_file_count_progression() {
   645→        let scorer = ComplexityScorer::new();
   646→
   647→        let scores: Vec<u32> = (0..=25)
   648→            .map(|count| {
   649→                let context = TaskContext::new("Task").with_file_count(count);
   650→                scorer.score(&context).file_count_score
   651→            })
   652→            .collect();
   653→
   654→        // Scores should generally increase
   655→        for i in 1..scores.len() {
   656→            assert!(
   657→                scores[i] >= scores[i - 1] || scores[i] == 100,
   658→                "File count {} score {} should be >= {} score {}",
   659→                i, scores[i], i - 1, scores[i - 1]
   660→            );
   661→        }
   662→    }
   663→
   664→    #[test]
   665→    fn test_blocks_progression() {
   666→        let scorer = ComplexityScorer::new();
   667→
   668→        let no_blocks = TaskContext::new("Task").with_blocks(0);
   669→        let few_blocks = TaskContext::new("Task").with_blocks(3);
   670→        let many_blocks = TaskContext::new("Task").with_blocks(10);
   671→
